import React from 'react';
import { Link } from 'react-router-dom';
import ProjectCard from '../components/Projects/ProjectCard';
import TaskCard from '../components/Tasks/TaskCard';
import { useAuth } from '../context/AuthContext';
import '../styles/Dashboard.css';

const Dashboard = ({ projects, tasks, users }) => {
  const { currentUser } = useAuth();

  // Get user initials for avatar
  const getUserInitials = (name) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase();
  };

  // Format date to readable format
  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  // Prepare data for display
  const stats = {
    totalProjects: projects.length,
    totalTasks: tasks.length,
    completedTasks: tasks.filter(task => task.status === 'Completed').length,
    inProgressTasks: tasks.filter(task => task.status === 'In Progress').length,
    myTasks: tasks.filter(task => task.assignee_id === currentUser.id).length
  };

  const recentTasks = tasks
    .sort((a, b) => new Date(b.updated_at) - new Date(a.updated_at))
    .slice(0, 5);

  const recentActivity = [
    { id: 1, user: users[0], action: 'completed task', item: 'Homepage Design', time: '2 hours ago' },
    { id: 2, user: users[1], action: 'commented on', item: 'Mobile App Project', time: '4 hours ago' },
    { id: 3, user: users[2], action: 'updated', item: 'API Documentation', time: '1 day ago' },
    { id: 4, user: users[3], action: 'created', item: 'Marketing Assets', time: '2 days ago' },
  ];

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Welcome back, {currentUser.name}! 👋</h1>
        <p>Here's what's happening with your projects today.</p>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">📊</div>
          <div className="stat-content">
            <h3>{stats.totalProjects}</h3>
            <p>Total Projects</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-content">
            <h3>{stats.totalTasks}</h3>
            <p>Total Tasks</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🚀</div>
          <div className="stat-content">
            <h3>{stats.inProgressTasks}</h3>
            <p>In Progress</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">👤</div>
          <div className="stat-content">
            <h3>{stats.myTasks}</h3>
            <p>My Tasks</p>
          </div>
        </div>
      </div>

      <div className="dashboard-content">
        {/* Recent Tasks Section */}
        <div className="dashboard-section">
          <div className="section-header">
            <h2>Recent Tasks</h2>
            <Link to="/my-tasks" className="view-all">View All</Link>
          </div>
          <div className="tasks-grid">
            {recentTasks.map(task => {
              const project = projects.find(p => p.id === task.project_id);
              const assignee = users.find(u => u.id === task.assignee_id);

              return (
                <TaskCard 
                  key={task.id}
                  task={{
                    ...task,
                    project: project?.name || 'Unknown Project',
                    assignee: assignee?.name || 'Unassigned',
                    dueDate: formatDate(task.due_date)
                  }}
                />
              );
            })}
          </div>
        </div>

        <div className="dashboard-columns">
          {/* Projects Section */}
          <div className="dashboard-section">
            <div className="section-header">
              <h2>My Projects</h2>
              <Link to="/projects" className="view-all">View All</Link>
            </div>
            <div className="projects-grid">
              {projects.slice(0, 4).map(project => {
                const manager = users.find(u => u.id === project.manager_id);
                const projectTasks = tasks.filter(t => t.project_id === project.id);

                return (
                  <ProjectCard
                    key={project.id}
                    project={{
                      ...project,
                      manager: manager?.name || 'Unassigned',
                      taskCount: projectTasks.length,
                      completedTasks: projectTasks.filter(t => t.status === 'Completed').length
                    }}
                  />
                );
              })}
            </div>
          </div>

          {/* Recent Activity Section */}
          <div className="dashboard-section">
            <div className="section-header">
              <h2>Recent Activity</h2>
            </div>
            <div className="activity-list">
              {recentActivity.map(activity => (
                <div key={activity.id} className="activity-item">
                  <div className="activity-avatar">
                    {getUserInitials(activity.user.name)}
                  </div>
                  <div className="activity-details">
                    <p>
                      <strong>{activity.user.name}</strong> {activity.action} <strong>{activity.item}</strong>
                    </p>
                    <span className="activity-time">{activity.time}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
